INSERT INTO steam_requirements(steam_appid,pc_requirements,mac_requirements,linux_requirements) VALUES (4700,'{''minimum'': ''<strong>Minimum System Requirements:</strong><br>     <ul class="bb_ul"><li>MicrosoftÂź WindowsÂź 2000/XP<br>     </li><li>Celeron 1.5GHz Pentium 4Âź (1500MHz) or equivalent AMDÂź processor<br>     </li><li>512MB RAM<br>     </li><li>11GB of uncompressed free hard disk space<br>     </li><li>100% DirectXÂź 9.0c compatible 16-bit sound cardand latest drivers<br>     </li><li>100% WindowsÂź 2000/XP compatible mouse,keyboard and latest drivers<br>     </li><li>DirectXÂź 9.0c<br>     </li><li>128MB Hardware Accelerated video card with Shader 1 support and the latest drivers. Must be 100% DirectXÂź 9.0c compatible<br>     </li><li>1024 x 768 minimum display resolution<br>     </li><li>Internet (TCP / IP) play supported; Internet play requires broadband connection and latest drivers; LAN play requires Network card.</li></ul><strong>Important Note:</strong> Some cards may not be compatible with the 3D acceleration features utilized by Medieval II: Total War. Please refer to your hardware manufacturer for 100% DirectXÂź 9.0c compatibility.''}','{''minimum'': ''<strong>Minimum: </strong><br><br><ul class="bb_ul"><li><strong>OS:</strong>10.14<br></li><li><strong>Processor:</strong> Intel Core i3<br></li><li><strong>Memory:</strong> 4GB<br></li><li><strong>Graphics:</strong> NVIDIA GeForce GT 650M 512MB','');
