INSERT INTO steam_requirements(steam_appid,pc_requirements,mac_requirements,linux_requirements) VALUES (7860,'{''minimum'': ''Minimum<br>                    <ul class="bb_ul"><li><strong>Operating System: </strong>MicrosoftÂź WindowsÂź XP SP3,Vista SP1 *<br>                    </li><li><strong>Processor: </strong>IntelÂź Dual Core 2.0 GHz or AMDâą Athlonâą 4000+<br>                    </li><li><strong>Memory: </strong>XP â 1 GB RAM,Vista â 2 GB RAM<br>                    </li><li><strong>Hard Disk Space: </strong>7.5 GB + 1 GB Swap File<br>                    </li><li><strong>Video Card: </strong>3D Hardware Accelerator Card Required â 100% DirectX 9.0c compatible 256 MB Video Memory - ATIÂź Radeon X1600 or NvidiaÂź Geforce 6800  <strong>- NOTE: Nvidia 260 GTX &amp; Nvidia 280 GTX are not supported.</strong><br>                    </li><li><strong>Sound Card: </strong>DirectX 9.0c Compatible Sound Card<br>                    </li><li><strong>DirectXÂź Version: </strong>DirectXÂź 9.0c<br>                    </li></ul><strong>*</strong> This product does not support Windows 95/98/ME/2000/NT or XP x64/Vista x64.''','','');
INSERT INTO steam_requirements(steam_appid,pc_requirements,mac_requirements,linux_requirements) VALUES (7940,'{''minimum'': ''<strong>Minimum: </strong><br>     <ul class="bb_ul"><li><strong>Supported OS: </strong>MicrosoftÂź WindowsÂź XP/Vista (Windows 95/98/ME/2000 are unsupported)<br>     </li><li><strong>DirectX Version: </strong>Microsoft DirectX 9.0c (included)<br>     </li><li><strong>Processor: </strong>IntelÂź PentiumÂź 4 2.4 Ghz / AMD(R) 64 (TM)  2800+ / IntelÂź and AMDÂź 1.8 Ghz Dual Core Processor or better supported<br>     </li><li><strong>Memory: </strong>512MB RAM (WindowsÂź XP),768MB RAM (VistaÂź)<br>     </li><li><strong>Graphics: </strong>NVIDIA Geforce 6600 or better or ATI RadeonÂź 9800Pro or better<br>     </li><li><strong>Sound: </strong>100% DirectX 9.0c compatible sound card<br>     </li><li><strong>Hard Drive: </strong>8GB of free hard drive space<br>     </li><li><strong>Internet: </strong>Broadband connection and service required for multiplayer connectivity</li></ul>''}','{''minimum'': ''<strong>Minimum: </strong><br>     <ul class="bb_ul"><li><strong>Supported OS: </strong> 10.12 (Sierra) <br>     </li><li><strong>CPU Processor: </strong>Intel Core 2 Duo (Dual-Core)<br>     </li><li><strong>CPU Speed: </strong>2.2 GHz<br>     </li><li><strong>Memory: </strong>1 GB RAM<br>     </li><li><strong>Hard Disk Space: </strong>8 GB + 1 GB Swap File<br>     </li><li><strong>Graphics: </strong>NVIDIA Geforce 7300 or better or ATI Radeon X1600<br>     </li><li><strong>Video Memory: </strong>128 MB VRam<br>     </li><li><strong>Note: </strong>Intel Integrated GMA 950 and Intel Integrated X3100 are unsupported video chipsets</li></ul>''}','');
