INSERT INTO steam_requirements(steam_appid,pc_requirements,mac_requirements,linux_requirements) VALUES (12360,'{''minimum'': ''<ul class="bb_ul"><li><strong>Note:</strong> Multiplayer is not available in all countries,please visit <a href="https://steamcommunity.com/linkfilter/?url=http://www.gamesforwindows.com/live/countries" target="_blank" rel="noopener"  >www.gamesforwindows.com/live/countries</a> for details.                     There is no LAN ( Local Area Network ) Function provided within this game.                     Flatout Ultimate Carnage is an online multiplayer game that utilizes the Games For Windows Live option provided by Microsoft.                     <br><br></li><li> <strong>Note:</strong>                     Games for Windows â LIVE requires you to have an account set up to play online Multiplayer Games.                     Please see the following link <a href="https://steamcommunity.com/linkfilter/?url=http://www.gamesforwindows.com/live" target="_blank" rel="noopener"  >www.gamesforwindows.com/live</a> for more information. Features may change without notice. Subject to terms of use (at <a href="https://steamcommunity.com/linkfilter/?url=http://www.gamesforwindows.com/live/termsofuse/)" target="_blank" rel="noopener"  >www.gamesforwindows.com/live/termsofuse/)</a>.                                        <br><br></li><li><strong>Note:</strong> Steering Wheels are not supported with Flatout Ultimate Carnage. Keyboard and controller support only.<br><br></li><li><strong>Supported OS: </strong>Windows XP (32bit) Windows Vista (32/64bit)                     <br>     </li><li><strong>Processor: </strong> Intel Processor 2.2GHz or Higher / AMD 2.2GHz or Higher                     <br>     </li><li><strong>Memory: </strong>2GB or higher                     <br>     </li><li><strong>Graphics: </strong>DirectX 9.0c or higher supported graphics cards with 256MB of Memory. <br>Supported Cards: <br>                    Nvidia Geforce 7600 or higher,ATI Radeon X1800 or higher.<br>                    Integrated Graphics Chips and Laptops are not supported by this game.                                         <br>     </li><li><strong>DirectX Version: </strong>DirectX 9.0c                      <br>     </li><li><strong>Sound: </strong>DirectX 9.0c supported Soundcard.                     <br>     </li><li><strong>Hard Drive: </strong> 4.75 GB free hard disk space                     <br>     </li><li><strong>Controllers: </strong> XBOX 360 Controller for Windows.                     ( Drivers for the XBOX 360 controller can be obtained from <a href="https://steamcommunity.com/linkfilter/?url=http://www.microsoft.com/hardware/gaming/download.mspx" target="_blank" rel="noopener"  >http://www.microsoft.com/hardware/gaming/download.mspx</a> )                     Note:XBOX 360 Controller is preset and cannot be re-configured regarding the control options.                                          <br>     </li><li><strong>Keyboard/Mouse: </strong>PC Game Pad Controller ( Minimum 8 button controller ) <br>                    ( The Manufacturers driver must be installed for the game pad controller. Plug and Play controllers are not supported )                                                              </li></ul>''}','','');
