INSERT INTO steam_requirements(steam_appid,pc_requirements,mac_requirements,linux_requirements) VALUES (13530,'{''minimum'': ''<p><strong>Minimum: </strong></p>      <ul>      <li><strong>Supported OS:</strong> Windows&reg; 2000/XP (only)</li>      <li><strong>Processor:</strong> 1.0 GHz AMD Athlon or Intel Pentium III (1.5 GHz Pentium IV or AMD Athlon recommended) </li>      <li><strong>Memory:</strong> 256 MB (512 MB recommended) </li>      <li><strong>Graphics:</strong>32 MB DirectX 9.0c compliant (128 MB recommended) (see supported list*) </li>      <li><strong>DirectX:</strong> DirectX 9.0c</li>      <li><strong>Sound</strong> DirectX 9.0c compliant (Dolby Digital Live required for Dolby Digital audio)      <li><strong>Hard Drive:</strong>1.5 GB</li>       <li><strong>Peripherals:</strong> Windows-compatible gamepad</li>       <li><strong>*Supported video cards at time of retail release:</strong> ATI 7500/8500/9000/X series,NVIDIA GeForce 3/4/FX/6/7 series (GeForce 4 MX not supported); Laptop versions of these chipsets may work but are not supported. For an up-to-date list of supported chipsets,video cards','','');
