INSERT INTO steam_requirements(steam_appid,pc_requirements,mac_requirements,linux_requirements) VALUES (35700,'{''minimum'': ''<strong> SYSTEM REQUIREMENTS FOR TRINE ENCHANTED EDITION </strong><br><ul class="bb_ul"><li><strong>OS:</strong> Windows 8 / 7 / Vista / XP<br>           </li><li><strong>Processor:</strong> 2.0 GHz CPU (Dual Core recommended) <br>           </li><li><strong>Memory:</strong> 1 GB<br>           </li><li><strong>Hard Disk Space:</strong> 4.0 GB  <br>           </li><li><strong>Video Card:</strong> ATi Radeon HD 2400 or NVIDIA GeForce 7600 or better (Shader Model 3.0 needs to be supported)<br>           </li><li><strong>DirectXÂź:</strong> 9.0c<br>           </li><li><strong>Sound:</strong> DirectX 9.0c compatible <br>           </li><li><strong>Additional:</strong> *Please note that Trine Enchanted Edition may not run on most Intel graphics solutions used in 2004-2009. The game does run on new (2010-) Intel HD Graphics 3000 or better.</li></ul><br><strong> SYSTEM REQUIREMENTS FOR TRINE </strong><br><ul class="bb_ul"><li><strong>OS:</strong> Windows XP,Windows Vista or Windows 7<br>          </li><li><strong>Processor:</strong> 2.0 GHz CPU (Dual-core recommended)<br>          </li><li><strong>Memory:</strong> 512 MB (XP),1 GB (Vista)<br>          </li><li><strong>Hard Disk Space:</strong> 4.0 GB<br>          </li><li><strong>Video Card:</strong> Radeon X800 or GeForce 6800 or better*<br>          </li><li><strong>DirectXÂź:</strong> 9.0c<br>          </li><li><strong>Sound:</strong> DirectX compatible soundcard (not required)<br>          </li><li><strong>Additional:</strong> Gamepads required for co-op play.<br>          <br><br>*Please note that Trine does not run on most Intel integrated graphics chipsets.<br>         </li></ul>''}','','');
INSERT INTO steam_requirements(steam_appid,pc_requirements,mac_requirements,linux_requirements) VALUES (35720,'{''minimum'': ''<ul class="bb_ul"><li><strong>OS:</strong> Windows 8 / 7 / Vista / XP<br>           </li><li><strong>Processor:</strong> 2.0 GHz CPU (Dual Core recommended) <br>           </li><li><strong>Memory:</strong> 1 GB<br>           </li><li><strong>Hard Disk Space:</strong> 4.5 GB  <br>           </li><li><strong>Video Card:</strong> ATi Radeon HD 2400 or NVIDIA GeForce 7600 or better (Shader Model 3.0 needs to be supported)<br>           </li><li><strong>DirectXÂź:</strong> 9.0c<br>           </li><li><strong>Sound:</strong> DirectX 9.0c compatible <br>           </li><li><strong>Additional:</strong> *Please note that Trine 2 may not run on most Intel graphics solutions used in 2004-2009. The game does run on new (2010-) Intel HD Graphics 3000 or better.</li></ul>''}','{''minimum'': ''<ul class="bb_ul"><li><strong>OS:</strong> OS X version Lion 10.7,or later.<br>            </li><li><strong>Processor:</strong> Intel Mac<br>            </li><li><strong>Memory:</strong> 1 GB RAM<br>            </li><li><strong>Hard Disk Space:</strong> 4.0 GB <br>            </li><li><strong>Video Card:</strong> NVIDIA GeForce 8600M or better / ATi Radeon 2400 or better*<br><br>           *NOTE: Please be advised that Trine 2 does not run on Intel graphics solutions used in 2006-2008. The game does run on new (2010-) Intel HD Graphics 3000 or better. Macs with NVIDIA GeForce 9400M or ATi Radeon X1600 may not achieve smooth gameplay.<br>            </li><li><strong>Additional:</strong> Keyboard','');
