INSERT INTO steam_requirements(steam_appid,pc_requirements,mac_requirements,linux_requirements) VALUES (46290,'{''minimum'': ''<strong>Minimum:</strong><br><ul class="bb_ul"><li><strong>OS:</strong> Windows XP SP3<br></li><li><strong>Processor:</strong> 2 Ghz+ Pentium 4 or Athlon XP<br></li><li><strong>Memory:</strong> 1 GB RAM<br></li><li><strong>Graphics:</strong> A dedicated video card with full OpenGL 2.1 support (starting from GeForce 5700/Radeon 9600)<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 4 GB available space<br></li><li><strong>Additional Notes:</strong> The game is not guaranteed to run on integrated graphics and laptops</li></ul>'',''recommended'': ''<strong>Recommended:</strong><br><ul class="bb_ul"><li><strong>OS:</strong> 64-bit Windows 7 and later<br></li><li><strong>Processor:</strong> 3 Ghz+ Intel or AMD chip<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> A dedicated video card with full OpenGL 2.1 support (starting from GeForce 5700/Radeon 9600)<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 4 GB available space<br></li><li><strong>Additional Notes:</strong> The game is not guaranteed to run on integrated graphics and laptops</li></ul>''}','[]','');
